#include <stdio.h>
#include <string.h>

void reverse(char* str) {
    char *start = str;
    char *end = str + strlen(str) - 1;
    char temp;
    while (start < end) {
        temp = *start;
        *start = *end;
        *end = temp;
        start++;
        end--;
    }
}

int main() {
    char str[101];
    int i = 0; char c;
    while (i < 100 && (c = getchar()) != '\n' && c != EOF) str[i++] = c;
    str[i] = 0;
    if (i > 0) {
        reverse(str);
        printf("%s\n", str);
    }
    return 0;
}
